SELECT
  'ENG5-L001', sub.id, 5, 'Intro', 45,
  'Lekcja organizacyjna.', 'Lekcja organizacyjna.',
  'Uczeń realizuje lekcję „Lekcja organizacyjna.” — Starter (Flash Klasa 5, A1).', 'Uczeń realizuje lekcję „Lekcja organizacyjna.” — Starter (Flash Klasa 5, A1).',
  '• Temat lekcji (RM): Lekcja organizacyjna.
